import{_ as t,o,c as i,a3 as n}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"84. Best Practice Employment Commitment Committee And","description":"","frontmatter":{"title":"84. Best Practice Employment Commitment Committee And","eba":"Allied Health Professionals 2021-2026","topics":["union-matters"]},"headers":[],"relativePath":"ebas/allied-health/union-matters/84-best-practice-employment-commitment-committee-and.md","filePath":"ebas/allied-health/union-matters/84-best-practice-employment-commitment-committee-and.md"}'),r={name:"ebas/allied-health/union-matters/84-best-practice-employment-commitment-committee-and.md"};function s(a,e,m,p,l,c){return o(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="_84-best-practice-employment-commitment-committee-and" tabindex="-1">84. Best Practice Employment Commitment Committee And <a class="header-anchor" href="#_84-best-practice-employment-commitment-committee-and" aria-label="Permalink to &quot;84. Best Practice Employment Commitment Committee And&quot;">​</a></h1><p>Classification Review</p><p><strong>84.1</strong> A Best Practice Employment Commitment Committee (BPECC) will be established during the life of the Agreement and will meet to discuss matters including:</p><p><strong>(a)</strong> implementation of the Agreement;</p><p><strong>(b)</strong> measures to support and improve understanding of and compliance with this Agreement;</p><p><strong>(c)</strong> potential agreed best practice guides to support implementation of and compliance with this Agreement;</p><p><strong>(d)</strong> any legislative requirement to undertake gender equity activities;</p><p><strong>(e)</strong> consolidation of major enterprise agreement provisions to reduce complexity and inefficiencies within the public health system, save that there will also be discussions on this matter involving all relevant health unions;</p><p><strong>(f)</strong> template Change Impact Statements (CIS);</p><p><strong>(g)</strong> review the following classifications, including their structures:</p><p><strong>(i)</strong> AHP1 management;</p><p><strong>(ii)</strong> Sonography;</p><p><strong>(iii)</strong> AHP2;</p><p><strong>(h)</strong> develop Pastoral Carer (Spiritual Carer) and Diversional Therapist classifications;</p><p><strong>(i)</strong> review of meal breaks for Employees rostered for shift duty at subclause 49.1(a)(ii);</p><p><strong>(j)</strong> develop workforce survey in relation to the use of Contractors and Labour Hire as described at <a href="/eba/ebas/allied-health/classification-staffing/94-contractors-and-labour-hire.html">clause 94</a>; and</p><p><strong>(k)</strong> discuss arrangements for building increased relief staff size, which could include sector-wide or internal relief bank/s as described at subclause 91.8(c).</p><p><strong>84.2</strong> The Committee will schedule a minimum of six (6) meetings per year.</p><p><strong>84.3</strong> The Committee will comprise nominated representatives from the Union, the VHIA and Department (as required). The Committee may, by agreement, establish sub-groups or delegate individual matters to a relevant health service(s) and/or Union members as required.</p><p><strong>84.4</strong> Classification Review</p><p><strong>(a)</strong> During the life of this Agreement the Allied Health Professionals Research and Practice Centre (however titled) will review and propose amendments to the following classifications, and their rates of pay (subject to subclause 84.4(b)):</p><p><strong>(i)</strong> Community Development Worker;</p><p><strong>(ii)</strong> Social Worker;</p><p><strong>(iii)</strong> Youth Worker; and</p><p><strong>(iv)</strong> Welfare Worker.</p><p><strong>(b)</strong> The objective of the review is to:</p><p><strong>(i)</strong> develop a classification structure that is contemporary and reflects the work performed by the Employees in these professions;</p><p><strong>(ii)</strong> clearly outline the relevant qualification types and/or experience that classify Employees in each of these professions;</p><p><strong>(iii)</strong> clearly distinguish between these professions based on the work performed, the Employee’s qualification, skills, knowledge and / or their experience;</p><p><strong>(iv)</strong> consider the rates of pay compared with the amended rates of pay of employees in these professions in Victoria covered by the Social, Community, Home Care and Disability Services Industry Award 2010 resulting from the equal remuneration order and advise whether the rates of pay of these professions in the Agreement should be amended as a result, and if so, by what amount; and</p><p><strong>(v)</strong> support the recruitment and retention of Employees in these professions.</p><p><strong>(c)</strong> The Union, VHIA and the Department will develop Terms of Reference, within one (1) year of this Agreement coming into effect that will:</p><p><strong>(i)</strong> reflect subclause 84.4(a) and (b);</p><p><strong>(ii)</strong> have regard to the Health Promotion Officer (Practitioner) classification; and</p><p><strong>(iii)</strong> provide for the Union, VHIA and Department to be part of the review.</p><p><strong>(d)</strong> From 7 July 2022, where an Employee or a position is classified as a Social Worker Employee/position, the Employee’s role/the position will not be restructured to a classification that is not a Social Worker classification:</p><p><strong>(i)</strong> during the life of this Agreement;</p><p><strong>(ii)</strong> before the implementation of the outcome of the review referred to at 84.4(a) (or other outcome as agreed); whichever, occurs sooner.</p><p>Plain language terms: BPEC.</p>',39)])])}const g=t(r,[["render",s]]);export{h as __pageData,g as default};
